"use client";
import { useEnvironmentContext } from "../../providers/environment/use-environment-context.js";
import { useLocaleContext } from "../../providers/locale/use-locale-context.js";
import * as navigationMenu from "@zag-js/navigation-menu";
import { useId } from "react";
import { normalizeProps, useMachine } from "@zag-js/react";
//#region src/components/navigation-menu/use-navigation-menu.ts
var useNavigationMenu = (props) => {
	const id = useId();
	const { getRootNode } = useEnvironmentContext();
	const { dir } = useLocaleContext();
	const machineProps = {
		id,
		dir,
		getRootNode,
		...props
	};
	const service = useMachine(navigationMenu.machine, machineProps);
	return navigationMenu.connect(service, normalizeProps);
};
//#endregion
export { useNavigationMenu };
